- (UICollectionReusableView *)collectionView:(UICollectionView *)collectionView viewForSupplementaryElementOfKind:(NSString *)kind atIndexPath:(NSIndexPath *)indexPath {
    if ([kind isEqualToString:UICollectionElementKindSectionHeader]) {
        UICollectionReusableView *header = [collectionView dequeueReusableSupplementaryViewOfKind:kind withReuseIdentifier:@"TopHeader" forIndexPath:indexPath];

        // 避免重复添加子视图
        if (header.subviews.count == 0) {
            CGFloat padding = ZOOMW(16);
            CGFloat hSpacing = ZOOMW(11);
            CGFloat vSpacing = ZOOMW(6);
            CGFloat halfWidth = ZOOMW(166);
            CGFloat smallHeight = ZOOMW(66);
            CGFloat bigHeight = ZOOMW(133);

            // 左侧大卡片
            UIButton *bigCard = [UIButton buttonWithType:UIButtonTypeCustom];
            bigCard.tag = 0;
            [bigCard setBackgroundImage:[UIImage imageNamed:[NSString stringWithFormat:@"A_%@", PasswordBroadcastAssetSuffix(self.displaytypes[0].type)]] forState:UIControlStateNormal];
            bigCard.imageView.contentMode = UIViewContentModeScaleToFill;
            [bigCard addTarget:self action:@selector(headerCardTapped:) forControlEvents:UIControlEventTouchUpInside];
            [header addSubview:bigCard];

            // 右上小卡片
            UIButton *topRightCard = [UIButton buttonWithType:UIButtonTypeCustom];
            topRightCard.tag = 1;
            [topRightCard setBackgroundImage:[UIImage imageNamed:[NSString stringWithFormat:@"A_%@", PasswordBroadcastAssetSuffix(self.displaytypes[1].type)]] forState:UIControlStateNormal];
            topRightCard.imageView.contentMode = UIViewContentModeScaleToFill;
            [topRightCard addTarget:self action:@selector(headerCardTapped:) forControlEvents:UIControlEventTouchUpInside];
            [header addSubview:topRightCard];

            // 右下小卡片
            UIButton *bottomRightCard = [UIButton buttonWithType:UIButtonTypeCustom];
            bottomRightCard.tag = 2;
            [bottomRightCard setBackgroundImage:[UIImage imageNamed:[NSString stringWithFormat:@"A_%@", PasswordBroadcastAssetSuffix(self.displaytypes[2].type)]] forState:UIControlStateNormal];
            bottomRightCard.imageView.contentMode = UIViewContentModeScaleToFill;
            [bottomRightCard addTarget:self action:@selector(headerCardTapped:) forControlEvents:UIControlEventTouchUpInside];
            [header addSubview:bottomRightCard];

            [bigCard mas_makeConstraints:^(MASConstraintMaker *make) {
                make.left.equalTo(header).offset(padding);
                make.top.equalTo(header);
                make.width.mas_equalTo(halfWidth);
                make.height.mas_equalTo(bigHeight);
            }];

            [topRightCard mas_makeConstraints:^(MASConstraintMaker *make) {
                make.right.equalTo(header).offset(-padding);
                make.top.equalTo(header);
                make.width.mas_equalTo(halfWidth);
                make.height.mas_equalTo(smallHeight);
            }];

            [bottomRightCard mas_makeConstraints:^(MASConstraintMaker *make) {
                make.right.equalTo(header).offset(-padding);
                make.top.equalTo(topRightCard.mas_bottom).offset(vSpacing);
                make.width.mas_equalTo(halfWidth);
                make.height.mas_equalTo(smallHeight);
            }];
        }

        return header;
    }
    return [[UICollectionReusableView alloc] init];
}

- (CGSize)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout referenceSizeForHeaderInSection:(NSInteger)section {
    CGFloat headerHeight = ZOOMW(133) + ZOOM(12);
    return CGSizeMake(collectionView.bounds.size.width, headerHeight);
}

