@implementation PasswordBroadcastSelectorPopupView

- (instancetype)initWithItems:(NSArray<NSString *> *)items {
    self = [super init];
    if (self) {
        self.items = items;
        self.selectedIndex = 0;
        self.frame = [UIScreen mainScreen].bounds;
    }
    return self;
}

#pragma mark - Show

- (void)showFromView:(UIView *)sourceView inView:(UIView *)parentView {
    self.sourceView = sourceView;

    // ① 将自己加到父 view
    [parentView addSubview:self];

    // 设置自己的约束，确保覆盖整个父视图
    [self mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(parentView);
    }];

    // ② 添加 subviews
    [self addSubview:self.contentView];
    [self.contentView addSubview:self.collectionView];

    CGFloat height = self.items.count * 50 + 20;

    // ③ 先设置contentView的初始位置（屏幕外左侧）
    [self.contentView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.width.mas_equalTo(160);
        make.height.mas_equalTo(height);
        make.left.equalTo(self).offset(300); // 初始在屏幕左侧外
        make.top.equalTo(self).offset(0); // 先给个默认值，后面会更新
    }];

    [self.collectionView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.contentView).insets(UIEdgeInsetsMake(10, 0, 10, 0));
    }];

    // ④ 强制布局更新，确保能获取正确的frame
    [self layoutIfNeeded];
    [parentView layoutIfNeeded];

    // ⑤ 计算按钮在self坐标系中的位置
    CGRect btnFrame = [sourceView.superview convertRect:sourceView.frame toView:self];

    // 计算弹窗应该在按钮的左边
    CGFloat popX = CGRectGetMinX(btnFrame) - 160 - 8; // 弹窗宽度160，再减去8的间距
    CGFloat popY = CGRectGetMinY(btnFrame);

    // 检查是否会超出屏幕左边界
    if (popX < 8) {
        popX = 8; // 保持最小边距
    }

    // 检查是否会超出屏幕上边界
    CGFloat maxY = popY + height;
    CGFloat screenHeight = CGRectGetHeight(self.bounds);
    if (maxY > screenHeight) {
        // 如果超出下边界，向上调整
        popY = screenHeight - height - 8;
    }

    // ⑥ 移除旧约束，添加新约束
    [self.contentView mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.width.mas_equalTo(160);
        make.height.mas_equalTo(height);
        make.left.equalTo(self).offset(popX);
        make.top.equalTo(self).offset(popY);
    }];

    // ⑦ 动画效果
    self.contentView.alpha = 0;
    self.contentView.transform = CGAffineTransformMakeScale(0.8, 0.8);

    [UIView animateWithDuration:0.25 animations:^{
        self.contentView.alpha = 1;
        self.contentView.transform = CGAffineTransformIdentity;
        [self layoutIfNeeded];
    }];
}
#pragma mark - Hide

- (void)hide {
    [UIView animateWithDuration:0.18 animations:^{
        self.contentView.alpha = 0;
    } completion:^(BOOL finished) {
        [self removeFromSuperview];
    }];
}

#pragma mark - UICollectionView

- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.items.count;
}

- (__kindof UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {

    PasswordBroadcastCategoryCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"PasswordBroadcastCategoryCell" forIndexPath:indexPath];
    cell.titleLabel.text = self.items[indexPath.item];
    [cell setChecked:(indexPath.item == self.selectedIndex)];
    return cell;
}

- (void)collectionView:(UICollectionView *)collectionView didSelectItemAtIndexPath:(NSIndexPath *)indexPath {

    self.selectedIndex = indexPath.item;
    [collectionView reloadData];

    if (self.selectCallback) {
        self.selectCallback(self.items[indexPath.item], indexPath.item);
    }
    [self hide];
}

