static NSString *PBTypeDisplayName(NSString *type) {
    static NSDictionary<NSString *, NSString *> *mapping;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        mapping = @{
            @"社交" : @"Social",
            @"邮箱" : @"Mail",
            @"游戏" : @"Game",
            @"工作" : @"Work",
            @"网站" : @"Website",
            @"其他" : @"Other"
        };
    });
    return mapping[type] ?: @"Social";
}

static NSString *PBTypeAssetName(NSString *type) {
    static NSDictionary<NSString *, NSString *> *mapping;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        mapping = @{
            @"社交" : @"A_Social",
            @"邮箱" : @"A_Mail",
            @"游戏" : @"A_Game",
            @"工作" : @"A_Work",
            @"网站" : @"A_Social",
            @"其他" : @"A_Social"
        };
    });
    return mapping[type] ?: @"A_Social";
}

