@implementation PasswordBroadcastAccountAddViewController

- (instancetype)init {
    self = [super init];
    if (self) {
        self.Account = [[PasswordBroadcastAccountModel alloc] init];
        self.isNewAcc = YES;
        self.selectedTypeKey = @"社交";
        self.modalPresentationStyle = UIModalPresentationOverFullScreen;
        self.modalTransitionStyle = UIModalTransitionStyleCrossDissolve;
    }
    return self;
}

- (instancetype)initWithAccount:(PasswordBroadcastAccountModel *)account {
    self = [super init];
    if (self) {
        self.Account = account;
        self.isNewAcc = NO;
        self.selectedTypeKey = account.type.length > 0 ? account.type : @"社交";
        self.modalPresentationStyle = UIModalPresentationOverFullScreen;
        self.modalTransitionStyle = UIModalTransitionStyleCrossDissolve;
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = UIColor.clearColor;
    [self setupUI];
    [self setupConstraints];
    [self applyAccountValues];
    [self refreshTypeDisplay];

    self.speechSynthesizer = [[AVSpeechSynthesizer alloc] init];
    self.speechSynthesizer.delegate = self;

    UITapGestureRecognizer *keyboardTap = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(hideKeyboard)];
    keyboardTap.cancelsTouchesInView = NO;
    [self.sheetView addGestureRecognizer:keyboardTap];
}

- (void)viewDidAppear:(BOOL)animated {
    [super viewDidAppear:animated];
    if (self.hasPresentedAnimation) {
        return;
    }
    self.hasPresentedAnimation = YES;
    CGFloat offset = MAX(CGRectGetHeight(self.view.bounds) * 0.7, 420);
    self.sheetView.transform = CGAffineTransformMakeTranslation(0, offset);
    self.dimmingView.alpha = 0;
    [UIView animateWithDuration:0.25
                          delay:0
                        options:UIViewAnimationOptionCurveEaseOut
                     animations:^{
        self.sheetView.transform = CGAffineTransformIdentity;
        self.dimmingView.alpha = 1.0;
    } completion:nil];
}

