#import "PasswordBroadcastTypeViewController.h"
#import "PasswordBroadcastAccountCell.h"
#import "PasswordBroadcastAccountAddViewController.h"

static NSString *PasswordBroadcastTypeEnglishTitle(NSString *type) {
    static NSDictionary<NSString *, NSString *> *mapping;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        mapping = @{
            @"社交" : @"Social account",
            @"邮箱" : @"Mail account",
            @"游戏" : @"Game account",
            @"工作" : @"Work account",
            @"网站" : @"Website account",
            @"其他" : @"Other account"
        };
    });
    return mapping[type] ?: type;
}

@interface PasswordBroadcastTypeViewController () <UICollectionViewDataSource, UICollectionViewDelegate, UICollectionViewDelegateFlowLayout>

@property (nonatomic, strong) UIView *topBar;
@property (nonatomic, strong) UIButton *backButton;
@property (nonatomic, strong) UILabel *titleLabel;
@property (nonatomic, strong) UIButton *trashButton;
@property (nonatomic, strong) UICollectionView *collectionView;
@property (nonatomic, strong) UILabel *emptyLabel;

@property (nonatomic, strong) NSArray<PasswordBroadcastAccountModel *> *displayAccs;
@property (nonatomic, strong) PasswordBroadcastTypeModel *Type;

@end

@implementation PasswordBroadcastTypeViewController

- (instancetype)init {
    self = [super init];
    if (self) {
        self.text = @"Search";
        self.displayAccs = [PasswordBroadcastAccountModel allAccs];
        self.view.backgroundColor = WHITE_COLOR;
        self.modalPresentationStyle = UIModalPresentationFullScreen;
    }
    return self;
}

- (instancetype)initWithType:(PasswordBroadcastTypeModel *)type {
    self = [super init];
    if (self) {
        self.Type = type;
        self.text = type.type;
        self.view.backgroundColor = WHITE_COLOR;
        self.modalPresentationStyle = UIModalPresentationFullScreen;
        [self loadAccounts];
        [PasswordBroadcastTypeModel updateType:self.Type];
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    [self setupUI];
    [self setupConstraints];
    [self reloadEmptyState];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleAccountUpdate) name:@"AccountDataUpdated" object:nil];
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (void)loadAccounts {
    NSPredicate *predicate = [NSPredicate predicateWithFormat:@"type == %@", self.text];
    self.displayAccs = [[PasswordBroadcastAccountModel allAccs] filteredArrayUsingPredicate:predicate];
}

- (void)handleAccountUpdate {
    [self loadAccounts];
    [self.collectionView reloadData];
    [self reloadEmptyState];
}

- (void)reloadEmptyState {
    BOOL hasAccounts = self.displayAccs.count > 0;
    self.emptyLabel.hidden = hasAccounts;
    self.collectionView.hidden = !hasAccounts;
}

#pragma mark - UI

- (void)setupUI {
    self.view.backgroundColor = WHITE_COLOR;
    [self.view addSubview:self.topBar];
    [self.topBar addSubview:self.backButton];
    [self.topBar addSubview:self.titleLabel];
    [self.topBar addSubview:self.trashButton];
    [self.view addSubview:self.collectionView];
    [self.view addSubview:self.emptyLabel];

    self.titleLabel.text = PasswordBroadcastTypeEnglishTitle(self.text);
}

- (void)setupConstraints {
    [self.topBar mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.left.right.equalTo(self.view);
        make.height.mas_equalTo(ZOOMW(88));
    }];

    [self.backButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.topBar).offset(ZOOMW(16));
        make.bottom.equalTo(self.topBar).offset(-ZOOMW(12));
        make.size.mas_equalTo(CGSizeMake(ZOOMW(24), ZOOMW(24)));
    }];

    [self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.topBar);
        make.centerY.equalTo(self.backButton);
    }];

    [self.trashButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.topBar).offset(-ZOOMW(16));
        make.centerY.equalTo(self.backButton);
        make.size.mas_equalTo(CGSizeMake(ZOOMW(24), ZOOMW(24)));
    }];

    [self.collectionView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.topBar.mas_bottom).offset(ZOOMW(8));
        make.left.right.bottom.equalTo(self.view);
    }];

    [self.emptyLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.topBar.mas_bottom).offset(ZOOMW(64));
        make.centerX.equalTo(self.view);
    }];
}

#pragma mark - Actions

- (void)goBack {
    [self dismissViewControllerAnimated:YES completion:nil];
}

- (void)showDeleteHint {
}

#pragma mark - UICollectionView DataSource

- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.displayAccs.count;
}

- (__kindof UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    PasswordBroadcastAccountCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"PasswordBroadcastAccountCell" forIndexPath:indexPath];
    PasswordBroadcastAccountModel *account = self.displayAccs[indexPath.item];
    cell.Account = account;
    cell.nameLabel.text = account.name;
    cell.noteLabel.text = account.note.length > 0 ? account.note : account.account;
    return cell;
}

#pragma mark - UICollectionView Delegate

- (void)collectionView:(UICollectionView *)collectionView didSelectItemAtIndexPath:(NSIndexPath *)indexPath {
    PasswordBroadcastAccountAddViewController *accountVC = [[PasswordBroadcastAccountAddViewController alloc] initWithAccount:self.displayAccs[indexPath.item]];
    [self presentViewController:accountVC animated:NO completion:nil];
}

#pragma mark - UICollectionViewDelegateFlowLayout

- (CGSize)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout sizeForItemAtIndexPath:(NSIndexPath *)indexPath {
    CGFloat width = collectionView.bounds.size.width - ZOOMW(32);
    return CGSizeMake(width, ZOOMW(56));
}

- (UIEdgeInsets)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout insetForSectionAtIndex:(NSInteger)section {
    return UIEdgeInsetsMake(ZOOMW(8), ZOOMW(16), ZOOMW(16), ZOOMW(16));
}

- (CGFloat)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout minimumLineSpacingForSectionAtIndex:(NSInteger)section {
    return ZOOMW(14);
}

- (CGFloat)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout minimumInteritemSpacingForSectionAtIndex:(NSInteger)section {
    return 0;
}

#pragma mark - Lazy

- (UIView *)topBar {
    if (!_topBar) {
        _topBar = [[UIView alloc] init];
        _topBar.backgroundColor = WHITE_COLOR;
    }
    return _topBar;
}

- (UIButton *)backButton {
    if (!_backButton) {
        _backButton = [UIButton buttonWithType:UIButtonTypeSystem];
        UIImage *image = nil;
        if (@available(iOS 13.0, *)) {
            image = [UIImage systemImageNamed:@"chevron.left"];
        }
        [_backButton setImage:image forState:UIControlStateNormal];
        _backButton.tintColor = RGB(146, 146, 146);
        [_backButton addTarget:self action:@selector(goBack) forControlEvents:UIControlEventTouchUpInside];
    }
    return _backButton;
}

- (UILabel *)titleLabel {
    if (!_titleLabel) {
        _titleLabel = [[UILabel alloc] init];
        _titleLabel.font = [UIFont systemFontOfSize:18 weight:UIFontWeightSemibold];
        _titleLabel.textColor = RGB(77, 77, 77);
    }
    return _titleLabel;
}

- (UIButton *)trashButton {
    if (!_trashButton) {
        _trashButton = [UIButton buttonWithType:UIButtonTypeSystem];
        UIImage *image = nil;
        if (@available(iOS 13.0, *)) {
            image = [UIImage systemImageNamed:@"trash.fill"];
        }
        [_trashButton setImage:image forState:UIControlStateNormal];
        _trashButton.tintColor = RGB(255, 59, 48);
        _trashButton.userInteractionEnabled = NO;
    }
    return _trashButton;
}

- (UILabel *)emptyLabel {
    if (!_emptyLabel) {
        _emptyLabel = [[UILabel alloc] init];
        _emptyLabel.text = @"No account yet";
        _emptyLabel.textColor = RGB(160, 160, 160);
        _emptyLabel.font = [UIFont systemFontOfSize:15];
        _emptyLabel.hidden = YES;
    }
    return _emptyLabel;
}

- (UICollectionView *)collectionView {
    if (!_collectionView) {
        UICollectionViewFlowLayout *layout = [[UICollectionViewFlowLayout alloc] init];
        layout.scrollDirection = UICollectionViewScrollDirectionVertical;
        _collectionView = [[UICollectionView alloc] initWithFrame:CGRectZero collectionViewLayout:layout];
        _collectionView.dataSource = self;
        _collectionView.delegate = self;
        _collectionView.backgroundColor = WHITE_COLOR;
        _collectionView.alwaysBounceVertical = YES;
        _collectionView.showsVerticalScrollIndicator = NO;
        [_collectionView registerClass:[PasswordBroadcastAccountCell class] forCellWithReuseIdentifier:@"PasswordBroadcastAccountCell"];
    }
    return _collectionView;
}

@end

