    PasswordBroadcastAccountModel *account = self.displayAccs[indexPath.item];
    cell.Account = account;
    cell.nameLabel.text = account.name;
    cell.noteLabel.text = account.note.length > 0 ? account.note : account.account;
    cell.deleteMode = self.deleteMode;
    cell.selectedForDelete = [self.selectedAccountIds containsObject:@(account.accId)];
    return cell;
}

