- (void)collectionView:(UICollectionView *)collectionView didSelectItemAtIndexPath:(NSIndexPath *)indexPath {
    PasswordBroadcastAccountModel *account = self.displayAccs[indexPath.item];
    if (self.deleteMode) {
        NSNumber *accId = @(account.accId);
        if ([self.selectedAccountIds containsObject:accId]) {
            [self.selectedAccountIds removeObject:accId];
        } else {
            [self.selectedAccountIds addObject:accId];
        }
        [self updateDeleteModeUI];
        [collectionView reloadItemsAtIndexPaths:@[indexPath]];
        return;
    }

    PasswordBroadcastAccountAddViewController *accountVC = [[PasswordBroadcastAccountAddViewController alloc] initWithAccount:account];
    [self presentViewController:accountVC animated:NO completion:nil];
}

