#import "PasswordBroadcastTypeModel.h"

@implementation PasswordBroadcastTypeModel

+ (NSArray<NSString *> *)orderedTypeKeys {
    return @[@"Social", @"Mail", @"Game", @"Work", @"Website", @"Other"];
}

+ (NSString *)canonicalTypeKeyForValue:(NSString *)value {
    NSString *trimmedValue = [[value ?: @"" stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]] copy];
    if (trimmedValue.length == 0) {
        return @"";
    }

    static NSDictionary<NSString *, NSString *> *mapping;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        mapping = @{
            @"social" : @"Social",
            @"mail" : @"Mail",
            @"game" : @"Game",
            @"work" : @"Work",
            @"website" : @"Website",
            @"other" : @"Other",
            @"社交" : @"Social",
            @"邮箱" : @"Mail",
            @"游戏" : @"Game",
            @"工作" : @"Work",
            @"网站" : @"Website",
            @"其他" : @"Other"
        };
    });

    NSString *englishKey = mapping[trimmedValue.lowercaseString];
    if (englishKey.length > 0) {
        return englishKey;
    }
    englishKey = mapping[trimmedValue];
    return englishKey.length > 0 ? englishKey : trimmedValue;
}

+ (NSString *)accountTitleForTypeKey:(NSString *)typeKey {
    NSString *key = [self canonicalTypeKeyForValue:typeKey];
    return key.length > 0 ? [NSString stringWithFormat:@"%@ account", key] : @"Account";
}

+ (NSMutableArray<PasswordBroadcastTypeModel *> *)allTypes {
    static NSMutableArray *types = nil;
    static dispatch_once_t onceToken;

    dispatch_once(&onceToken, ^{
        types = [NSMutableArray array];

        NSArray *savedTypes = [NSArray arrayWithJsonFile:[self filePath] elementClass:[PasswordBroadcastTypeModel class]];
        NSMutableDictionary<NSString *, PasswordBroadcastTypeModel *> *typeLookup = [NSMutableDictionary dictionary];
        BOOL needsSave = NO;

        for (PasswordBroadcastTypeModel *type in savedTypes) {
            NSString *canonicalKey = [self canonicalTypeKeyForValue:type.type];
            if (canonicalKey.length == 0) {
                needsSave = YES;
                continue;
            }
            if (![type.type isEqualToString:canonicalKey]) {
                type.type = canonicalKey;
                needsSave = YES;
            }
            if (!type.createTime) {
                type.createTime = [NSDate date];
                needsSave = YES;
            }
            if (!typeLookup[canonicalKey]) {
                typeLookup[canonicalKey] = type;
            } else {
                needsSave = YES;
            }
        }

        for (NSString *typeKey in [self orderedTypeKeys]) {
            PasswordBroadcastTypeModel *type = typeLookup[typeKey];
            if (!type) {
                type = [[PasswordBroadcastTypeModel alloc] init];
                type.type = typeKey;
                type.createTime = [NSDate date];
                needsSave = YES;
            }
            [types addObject:type];
        }

        if (needsSave || savedTypes.count != types.count) {
            [types writeToJsonFile:[self filePath]];
        }
    });

    return types;
}

+ (void)saveTypes {
    for (PasswordBroadcastTypeModel *type in [PasswordBroadcastTypeModel allTypes]) {
        type.type = [self canonicalTypeKeyForValue:type.type];
    }
    [[PasswordBroadcastTypeModel allTypes] writeToJsonFile:[self filePath]];
}

+ (void)updateType:(PasswordBroadcastTypeModel *)type {
    type.type = [self canonicalTypeKeyForValue:type.type];
    type.updateTime = [NSDate date];
    [self saveTypes];
}

#pragma mark - Private

+ (NSString *)filePath {
    return [NSFileManager documentFilePathWithName:@"password_broadcast_types.json"];
}

@end

