#pragma mark - Actions

- (void)goBack {
    [self dismissViewControllerAnimated:YES completion:nil];
}

- (void)toggleDeleteMode {
    self.deleteMode = !self.deleteMode;
    if (!self.deleteMode) {
        [self.selectedAccountIds removeAllObjects];
    }
    [self updateDeleteModeUI];
    [self.collectionView reloadData];
}

- (void)updateDeleteModeUI {
    self.bottomDeleteButton.hidden = !self.deleteMode;
    UIEdgeInsets insets = self.deleteMode ? UIEdgeInsetsMake(0, 0, ZOOMW(76), 0) : UIEdgeInsetsZero;
    self.collectionView.contentInset = insets;
    self.collectionView.scrollIndicatorInsets = insets;
    BOOL hasSelection = self.selectedAccountIds.count > 0;
    self.bottomDeleteButton.enabled = hasSelection;
    self.bottomDeleteButton.alpha = hasSelection ? 1.0 : 0.45;
}

- (void)confirmDeleteSelectedAccounts {
    if (self.selectedAccountIds.count == 0) {
        return;
    }
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Delete"
                                                                   message:@"Once deleted, the account cannot be recovered."
                                                            preferredStyle:UIAlertControllerStyleAlert];
    [alert addAction:[UIAlertAction actionWithTitle:@"Cancel" style:UIAlertActionStyleCancel handler:nil]];
    [alert addAction:[UIAlertAction actionWithTitle:@"Delete" style:UIAlertActionStyleDestructive handler:^(UIAlertAction * _Nonnull action) {
        NSArray<NSNumber *> *selectedIds = self.selectedAccountIds.allObjects;
        for (NSNumber *accId in selectedIds) {
            [PasswordBroadcastAccountModel deleteAcc:accId.integerValue];
        }
        [self.selectedAccountIds removeAllObjects];
        self.deleteMode = NO;
        [[NSNotificationCenter defaultCenter] postNotificationName:@"AccountDataUpdated" object:nil];
        [self loadAccounts];
        [self.collectionView reloadData];
        [self reloadEmptyState];
        [self updateDeleteModeUI];
    }]];
    [self presentViewController:alert animated:YES completion:nil];
}

#pragma mark - UICollectionView DataSource

- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
